398	// RunInTransaction is implemented in transaction.go.
399	
400	// Close marks the store as closed and releases the exclusive flock on the data
401	// directory (if the store owns it). Subsequent method calls will return errClosed.
402	// It is safe to call multiple times. When the lock was supplied by the caller
403	// via WithLock, Close does NOT release it — the caller retains ownership.
404	func (s *EmbeddedDoltStore) Close() error {
405		// Use CompareAndSwap so we only unlock once even if Close is called
406		// multiple times (the Lock.Unlock method panics on double-unlock).
407		if s.closed.CompareAndSwap(false, true) {
408			if s.lock != nil && s.ownsLock {
409				s.lock.Unlock()
410			}
411		}
412		return nil
413	}
