422	// Flatten squashes all Dolt commit history into a single commit.
423	// Pins a single *sql.Conn for session-scoped stored procedures.
424	func (s *EmbeddedDoltStore) Flatten(ctx context.Context) error {
425		return s.withDBConn(ctx, func(db versioncontrolops.DBConn) error {
426			if pooled, ok := db.(*sql.DB); ok {
427				conn, err := pooled.Conn(ctx)
428				if err != nil {
429					return err
430				}
431				defer conn.Close()
432				return versioncontrolops.Flatten(ctx, conn)
433			}
434			return versioncontrolops.Flatten(ctx, db)
435		})
436	}
