438	// Compact squashes old Dolt commits while preserving recent ones.
439	// Pins a single *sql.Conn for session-scoped stored procedures.
440	func (s *EmbeddedDoltStore) Compact(ctx context.Context, initialHash, boundaryHash string, oldCommits int, recentHashes []string) error {
441		return s.withDBConn(ctx, func(db versioncontrolops.DBConn) error {
442			// withDBConn returns *sql.DB; pin a single connection for
443			// session-scoped operations (checkout, reset, cherry-pick).
444			if pooled, ok := db.(*sql.DB); ok {
445				conn, err := pooled.Conn(ctx)
446				if err != nil {
447					return err
448				}
449				defer conn.Close()
450				return versioncontrolops.Compact(ctx, conn, initialHash, boundaryHash, oldCommits, recentHashes)
451			}
452			return versioncontrolops.Compact(ctx, db, initialHash, boundaryHash, oldCommits, recentHashes)
453		})
454	}
