478		var hasPending bool
479		var msg string
480		err := s.withConn(ctx, false, func(tx *sql.Tx) error {
481			var err error
482			hasPending, err = issueops.HasPendingChanges(ctx, tx)
483			if err != nil {
484				return err
485			}
486			if hasPending {
487				msg = issueops.BuildBatchCommitMessage(ctx, tx, actor)
488			}
489			return nil
490		})
491		if err != nil {
492			return false, err
493		}
494		if !hasPending {
495			return false, nil
496		}
497	
498		if err := s.Commit(ctx, msg); err != nil {
499			if issueops.IsNothingToCommitError(err) {
500				return false, nil
501			}
502			return false, err
503		}
504		return true, nil
505	}
