1	//go:build cgo
2	
3	package embeddeddolt_test
4	
5	import (
6		"context"
7		"fmt"
8		"os"
9		"path/filepath"
10		"strings"
11		"testing"
12		"time"
13	
14		"github.com/steveyegge/beads/internal/storage/embeddeddolt"
15		"github.com/steveyegge/beads/internal/types"
16	)
17	
18	// testEnv bundles a store with the paths needed to open raw SQL connections.
19	type testEnv struct {
20		store    *embeddeddolt.EmbeddedDoltStore
21		dataDir  string
22		database string
23	}
24	
25	// newTestEnv creates an initialized EmbeddedDoltStore in a temp directory,
26	// sets the issue_prefix config, and returns a testEnv with raw SQL access.
27	func newTestEnv(t *testing.T, prefix string) *testEnv {
28		t.Helper()
29		ctx := t.Context()
30		beadsDir := filepath.Join(t.TempDir(), ".beads")
31		store, err := embeddeddolt.New(ctx, beadsDir, prefix, "main")
32		if err != nil {
33			t.Fatalf("New: %v", err)
34		}
35		t.Cleanup(func() { store.Close() })
36	
37		if err := store.SetConfig(ctx, "issue_prefix", prefix); err != nil {
38			t.Fatalf("SetConfig(issue_prefix): %v", err)
39		}
40		if err := store.Commit(ctx, "bd init"); err != nil {
41			t.Fatalf("Commit: %v", err)
42		}
43		return &testEnv{
44			store:    store,
45			dataDir:  filepath.Join(beadsDir, "embeddeddolt"),
46			database: prefix,
47		}
48	}
49	
50	// queryScalar opens a short-lived raw SQL connection, runs a single-row query,
51	// scans the results into dest, and closes the connection immediately.
52	func (te *testEnv) queryScalar(t *testing.T, ctx context.Context, query string, args []any, dest ...any) {
53		t.Helper()
54		db, cleanup, err := embeddeddolt.OpenSQL(ctx, te.dataDir, te.database, "main")
55		if err != nil {
56			t.Fatalf("OpenSQL: %v", err)
57		}
58		defer cleanup()
59		if err := db.QueryRowContext(ctx, query, args...).Scan(dest...); err != nil {
60			t.Fatalf("queryScalar %q: %v", query, err)
61		}
62	}
63	
64	// exec opens a short-lived raw SQL connection, executes a statement, and closes immediately.
65	func (te *testEnv) exec(t *testing.T, ctx context.Context, stmt string, args ...any) {
66		t.Helper()
67		db, cleanup, err := embeddeddolt.OpenSQL(ctx, te.dataDir, te.database, "main")
68		if err != nil {
69			t.Fatalf("OpenSQL: %v", err)
70		}
71		defer cleanup()
72		if _, err := db.ExecContext(ctx, stmt, args...); err != nil {
73			t.Fatalf("exec %q: %v", stmt, err)
74		}
75	}
76	
77	// assertRowExists verifies a row exists in the given table with the given ID.
78	func (te *testEnv) assertRowExists(t *testing.T, ctx context.Context, table, id string) {
79		t.Helper()
80		var count int
81		te.queryScalar(t, ctx, fmt.Sprintf("SELECT COUNT(*) FROM %s WHERE id = ?", table), []any{id}, &count)
82		if count == 0 {
83			t.Errorf("expected row in %s with id=%q, found none", table, id)
84		}
85	}
86	
87	// assertRowNotExists verifies no row exists in the given table with the given ID.
88	func (te *testEnv) assertRowNotExists(t *testing.T, ctx context.Context, table, id string) {
89		t.Helper()
90		var count int
91		te.queryScalar(t, ctx, fmt.Sprintf("SELECT COUNT(*) FROM %s WHERE id = ?", table), []any{id}, &count)
92		if count != 0 {
93			t.Errorf("expected no row in %s with id=%q, found %d", table, id, count)
94		}
95	}
96	
97	// assertIssueTitle verifies the title of an issue in the given table.
98	func (te *testEnv) assertIssueTitle(t *testing.T, ctx context.Context, table, id, wantTitle string) {
99		t.Helper()
100		var got string
101		te.queryScalar(t, ctx, fmt.Sprintf("SELECT title FROM %s WHERE id = ?", table), []any{id}, &got)
102		if got != wantTitle {
103			t.Errorf("title for %s: got %q, want %q", id, got, wantTitle)
104		}
105	}
106	
107	// assertEventCount verifies the number of events for an issue.
108	func (te *testEnv) assertEventCount(t *testing.T, ctx context.Context, table, issueID, eventType string, wantCount int) {
109		t.Helper()
110		var count int
111		te.queryScalar(t, ctx,
112			fmt.Sprintf("SELECT COUNT(*) FROM %s WHERE issue_id = ? AND event_type = ?", table),
