)

// TestWispTablesExistAfterInitSchema verifies that wisp tables exist
// after initSchema completes. This reproduces the bug where
// createIgnoredTables() is never called during embedded Dolt initialization.
func TestWispTablesExistAfterInitSchema(t *testing.T) {
	skipUnlessEmbeddedDolt(t)

	ctx := t.Context()
	beadsDir := filepath.Join(t.TempDir(), ".beads")
	dataDir := filepath.Join(beadsDir, "embeddeddolt")
	database := "wt"

	// ---- Session 1: initialize the store (runs all schema migrations) ----
	store, err := embeddeddolt.New(ctx, beadsDir, database, "main")
	if err != nil {
		t.Fatalf("New (session 1): %v", err)
	}
	store.Close()

	// ---- Session 2: open a new store (migrations already applied, initSchema fast path) ----
	store2, err := embeddeddolt.New(ctx, beadsDir, database, "main")
	if err != nil {
		t.Fatalf("New (session 2): %v", err)
	}
	defer store2.Close()

	// Check that wisp tables exist in session 2.
	// Since they're dolt_ignore'd, they must be explicitly recreated by initSchema.
	db, cleanup, err := embeddeddolt.OpenSQL(ctx, dataDir, database, "main")
	if err != nil {
		t.Fatalf("OpenSQL: %v", err)
	}
	defer cleanup()

	wispTables := []string{"wisps", "wisp_dependencies", "wisp_labels", "wisp_events", "wisp_comments"}
	for _, table := range wispTables {
		var count int
		err := db.QueryRowContext(ctx,
			"SELECT COUNT(*) FROM information_schema.tables WHERE table_name = ? AND table_schema = ?",
			table, database).Scan(&count)
		if err != nil {
			t.Fatalf("checking table %s: %v", table, err)
		}
		if count == 0 {
			t.Errorf("table %s does NOT exist after session 2 initSchema (BUG: createIgnoredTables not called in embedded path)", table)
		}
	}
}

// TestDepAddWorksAfterInit reproduces the exact error from the bug report:
// `bd dep add` fails with "table not found: wisp_dependencies".
func TestDepAddReproducesBug(t *testing.T) {
	skipUnlessEmbeddedDolt(t)

	ctx := t.Context()
	beadsDir := filepath.Join(t.TempDir(), ".beads")

	// Session 1: init
	store, err := embeddeddolt.New(ctx, beadsDir, "da", "main")
	if err != nil {
		t.Fatalf("New (session 1): %v", err)
	}
	store.Close()

	// Session 2: this is the session that fails in the bug report
	store2, err := embeddeddolt.New(ctx, beadsDir, "da", "main")
	if err != nil {
		t.Fatalf("New (session 2): %v", err)
	}
	defer store2.Close()

	// Set up issue prefix (required for issue creation).
	if err := store2.SetConfig(ctx, "issue_prefix", "da"); err != nil {
		t.Fatalf("SetConfig: %v", err)
	}
	if err := store2.Commit(ctx, "init"); err != nil {
		t.Fatalf("Commit: %v", err)
	}

	// Create two issues (not wisps - standard issues).
	a := &types.Issue{Title: "A", Status: types.StatusOpen, Priority: 2, IssueType: types.TypeTask}
	b := &types.Issue{Title: "B", Status: types.StatusOpen, Priority: 2, IssueType: types.TypeTask}
	if err := store2.CreateIssue(ctx, a, "tester"); err != nil {
		t.Fatalf("CreateIssue A: %v", err)
	}
	if err := store2.CreateIssue(ctx, b, "tester"); err != nil {
		t.Fatalf("CreateIssue B: %v", err)
	}

	// This should succeed but fails because wisp_dependencies table doesn't exist
	// and the cycle detection CTE queries both tables (dependencies, wisp_dependencies).
	dep := &types.Dependency{IssueID: a.ID, DependsOnID: b.ID, Type: types.DepBlocks}
	if err := store2.AddDependency(ctx, dep, "tester"); err != nil {
		t.Errorf("AddDependency failed (BUG): %v", err)
	}
}

