//go:build cgo

package embeddeddolt_test

import (
	"context"
	"fmt"
	"path/filepath"
	"testing"

	"github.com/steveyegge/beads/internal/storage/embeddeddolt"
)

// TestWispTablesInCommitHistory verifies whether wisp tables appear in
// commit history after initial migration. Since they are dolt_ignore'd,
// they should NOT appear in commit history.
func TestWispTablesInCommitHistory(t *testing.T) {
	skipUnlessEmbeddedDolt(t)

	ctx := t.Context()
	beadsDir := filepath.Join(t.TempDir(), ".beads")
	dataDir := filepath.Join(beadsDir, "embeddeddolt")
	database := "wh"

	// Session 1: initialize
	store, err := embeddeddolt.New(ctx, beadsDir, database, "main")
	if err != nil {
		t.Fatalf("New: %v", err)
	}
	store.Close()

	// Open a raw connection to check what's committed.
	db, cleanup, err := embeddeddolt.OpenSQL(ctx, dataDir, database, "main")
	if err != nil {
		t.Fatalf("OpenSQL: %v", err)
	}
	defer cleanup()

	// Check if dolt_ignore patterns exist
	var ignoreCount int
	if err := db.QueryRowContext(ctx, "SELECT COUNT(*) FROM dolt_ignore WHERE pattern IN ('wisps', 'wisp_%')").Scan(&ignoreCount); err != nil {
		t.Fatalf("checking dolt_ignore: %v", err)
	}
	t.Logf("dolt_ignore patterns: %d", ignoreCount)

	// Check if wisps table exists (via information_schema)
	wispTables := []string{"wisps", "wisp_dependencies", "wisp_labels", "wisp_events", "wisp_comments"}
	for _, table := range wispTables {
		var count int
		err := db.QueryRowContext(ctx,
			"SELECT COUNT(*) FROM information_schema.tables WHERE table_name = ? AND table_schema = ?",
			table, database).Scan(&count)
		if err != nil {
			t.Fatalf("checking table %s: %v", table, err)
		}
		t.Logf("Table %s: exists=%v", table, count > 0)
	}

	// Check if tables are staged (should NOT be if dolt_ignore works)
	for _, table := range wispTables {
		var count int
		err := db.QueryRowContext(ctx,
			fmt.Sprintf("SELECT COUNT(*) FROM dolt_status WHERE table_name = '%s'", table)).Scan(&count)
		if err != nil {
			t.Logf("checking dolt_status for %s: %v", table, err)
		} else {
			t.Logf("Table %s in dolt_status: %d rows", table, count)
		}
	}

	// Now check dolt_log to see what was committed
	rows, err := db.QueryContext(ctx, "SELECT commit_hash, message FROM dolt_log LIMIT 5")
	if err != nil {
		t.Fatalf("dolt_log: %v", err)
	}
	defer rows.Close()
	t.Log("Dolt log:")
	for rows.Next() {
		var hash, msg string
		if err := rows.Scan(&hash, &msg); err != nil {
			t.Fatalf("scan: %v", err)
		}
		t.Logf("  %s: %s", hash, msg)
	}
}

