func TestDepAddReproducesBug(t *testing.T) {
	skipUnlessEmbeddedDolt(t)

	ctx := t.Context()
	beadsDir := filepath.Join(t.TempDir(), ".beads")

	// Session 1: init
	store, err := embeddeddolt.New(ctx, beadsDir, "da", "main")
	if err != nil {
		t.Fatalf("New (session 1): %v", err)
	}
	store.Close()

	// Session 2: this is the session that fails in the bug report
	store2, err := embeddeddolt.New(ctx, beadsDir, "da", "main")
	if err != nil {
		t.Fatalf("New (session 2): %v", err)
	}
	defer store2.Close()

	// Set up issue prefix (required for issue creation).
	if err := store2.SetConfig(ctx, "issue_prefix", "da"); err != nil {
		t.Fatalf("SetConfig: %v", err)
	}
	if err := store2.Commit(ctx, "init"); err != nil {
		t.Fatalf("Commit: %v", err)
	}

	// Create two issues (not wisps - standard issues).
	a := &types.Issue{Title: "A", Status: types.StatusOpen, Priority: 2, IssueType: types.TypeTask}
	b := &types.Issue{Title: "B", Status: types.StatusOpen, Priority: 2, IssueType: types.TypeTask}
	if err := store2.CreateIssue(ctx, a, "tester"); err != nil {
		t.Fatalf("CreateIssue A: %v", err)
	}
	if err := store2.CreateIssue(ctx, b, "tester"); err != nil {
		t.Fatalf("CreateIssue B: %v", err)
	}

	// This should succeed but fails because wisp_dependencies table doesn't exist
	// and the cycle detection CTE queries both tables (dependencies, wisp_dependencies).
	dep := &types.Dependency{IssueID: a.ID, DependsOnID: b.ID, Type: types.DepBlocks}
	if err := store2.AddDependency(ctx, dep, "tester"); err != nil {
		t.Errorf("AddDependency failed (BUG): %v", err)
	}
}

